mapper.select:
select a.*, u.user_tg_username as username
from t_amount_change a
left join t_user u on u.user_id = a.user_id
where a.id = #{id}
limit 1;

select *
from t_amount_change
where user_id = #{userId}
  and currency_id = #{currencyId}
order by id desc limit 1

select IFNULL(SUM(CASE WHEN account_type = 1 THEN amount ELSE 0 END), 0) AS income,
IFNULL(SUM(CASE WHEN account_type = 2 THEN amount ELSE 0 END), 0) AS expend
from t_amount_change

    user_id = #{userId}

        and type = #{type}

    and create_time BETWEEN #{startTime} AND #{endTime}

select l.account_type,l.amount
     from t_amount_change l left join t_user u on l.user_id = u.user_id


    and u.channel_id = #{channelId}


    and  l.currency_id=#{id}


    and l.create_time BETWEEN #{startTime} AND #{endTime}

select l.* from t_amount_change l left join t_user u on l.user_id = u.user_id


        u.channel_id = #{channelId}


        and l.create_time BETWEEN #{startTime} AND #{endTime}

select COUNT(DISTINCT u.user_id) from t_amount_change l inner join t_user u on l.user_id = u.user_id


        u.channel_id = #{channelId}


        and l.create_time BETWEEN #{startTime} AND #{endTime}

select
IFNULL(SUM(CASE WHEN account_type = 1 THEN amount ELSE 0 END),0) as userEarnings,
IFNULL(SUM(CASE WHEN account_type = 1 and order_type = 12 and type = 22 THEN amount ELSE 0 END),0) as
transferBonusAmount,
IFNULL(SUM(CASE WHEN account_type = 2 THEN amount ELSE 0 END),0) as userExpenses
from t_amount_change


        AND user_id = #{userId}


        AND currency_id = #{currencyId}


        AND create_time BETWEEN #{startTime} AND #{endTime}

select
count(l.id) as counts,
IFNULL(SUM(l.amount), 0) AS amount
from t_amount_change l left join t_user u on l.user_id = u.user_id


        and u.channel_id = #{channelId}


        and  l.currency_id=#{id}


       and  l.account_type=#{accountType}


       and  l.order_type=#{orderType}


        and l.create_time BETWEEN #{startTime} AND #{endTime}


        and  l.type=#{type}

SELECT COUNT(DISTINCT l.user_id)
FROM (
SELECT user_id
FROM t_amount_change


        AND create_time BETWEEN #{startTime} AND #{endTime}


) l
LEFT JOIN t_user u ON l.user_id = u.user_id


        AND u.channel_id = #{channelId}

select count(a.id)
from t_amount_change a
left join t_user u on u.user_id = a.user_id

        and a.user_id = #{userId}
        and a.tg_user_id = #{tgUserId}
        and a.currency_id = #{currencyId}
        and a.item_id = #{itemId}
        and a.chain_tag = #{chainTag}
        and a.item_name = #{itemName}
        and a.order_no = #{orderNo}
        and a.order_type = #{orderType}
        and a.exchange_type = #{exchangeType}
        and a.account_type = #{accountType}
        and a.type = #{type}
        and a.amount = #{amount}
        and a.old_amount = #{oldAmount}
        and a.new_amount = #{newAmount}
        and a.operator = #{operator}
        and a.sign_time = #{signTime}
        and a.sign = #{sign}
        and (


                    a.create_time between #{item,jdbcType=VARCHAR}


                    and #{item,jdbcType=VARCHAR}


            )

select COUNT(DISTINCT u.user_id) from t_amount_change l inner join t_user u on l.user_id = u.user_id


        u.shareholder_id = #{shareholderId}


        and l.create_time BETWEEN #{startTime} AND #{endTime}

SELECT SUM(b.new_amount) as total_new_amount
FROM (
SELECT user_id, new_amount,
ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY create_time DESC) as rn
FROM t_amount_change a
WHERE a.create_time <= #{endTime}

    AND a.user_id IN

        #{userId}


and a.currency_id = #{currencyId}
) b
WHERE b.rn = 1

mapper.delete:
DELETE FROM t_amount_change
where id <= #{maxId}
AND create_time <= NOW() - INTERVAL 1 HOUR
LIMIT 2000;

