SELECT u.user_id,u.user_tg_id,u.user_tg_name,u.user_tg_username, u.user_avatar, u.user_type, u.level, u.super_user_id,u.super_user_tg_id, u.salt,u.pay_password,u.google_key,u.lan_key,u.phone,u.email, u.freeze_status,u.handle_freeze_status,u.ip,u.ip_addr,u.channel_id, u.sign_time,u.sign, u.login_time, u.create_time, u.update_time, u.update_by,u.follow_status,u.has_set_rtp,u.bot_status FROM ( SELECT DISTINCT l.user_id FROM t_amount_change l
AND l.create_time BETWEEN #{startTime} AND #{endTime}
) temp LEFT JOIN t_user u ON temp.user_id = u.user_id

